class FoodRatings {
public:
    FoodRatings(vector<string>& foods, vector<string>& cuisines, vector<int>& ratings) {
        for (int i = 0; i < foods.size(); i++) {
            foodRatings[foods[i]] = make_pair(ratings[i], cuisines[i]);
            foodMap[cuisines[i]].push_back(foods[i]);
        }
        sort(foodMap.begin(), foodMap.end());
        for (auto& it : foodMap) {
            sort(it.second.begin(), it.second.end(), [](string a, string b) {
                return foodRatings[a].first > foodRatings[b].first || (foodRatings[a].first == foodRatings[b].first && a < b);
            });
        }
    }

    void changeRating(string food, int newRating) {
        int oldRating = foodRatings[food].first;
        foodRatings[food].first = newRating;
        int index = find(foodMap[foodRatings[food].second].begin(), foodMap[foodRatings[food].second].end(), food) - foodMap[foodRatings[food].second].begin();
        if (index > 0) {
            foodMap[foodRatings[food].second][index - 1].swap(food);
            sort(foodMap[foodRatings[food].second].begin(), foodMap[foodRatings[food].second].end(), [](string a, string b) {
                return foodRatings[a].first > foodRatings[b].first || (foodRatings[a].first == foodRatings[b].first && a < b);
            });
        }
    }

    string highestRated(string cuisine) {
        return foodMap[cuisine][0];
    }
private:
    map<string, pair<int, string>> foodRatings;
    map<string, vector<string>> foodMap;
};
